"use strict";const t=require("../utils/request.js");exports.auditApplication=(s,e,i)=>t.service.post(`/admin/merchant-applications/${s}/audit`,{status:e,rejectionReason:i}),exports.getActivityLogs=t=>Promise.resolve([{id:1,description:"系统初始化完成",timestamp:new Date,type:"success"},{id:2,description:"管理员登录",timestamp:new Date,type:"primary"}]),exports.getAdminStats=s=>t.service.get("/admin/stats",{params:{dimension:s}}),exports.getAllUsers=()=>t.service.get("/admin/users"),exports.getMerchantApplications=s=>t.service.get("/admin/merchant-applications",{params:{status:s}}),exports.updateUserStatus=(s,e)=>t.service.post(`/admin/users/${s}/status`,{status:e});
